from __future__ import annotations
import httpx
import logging
from typing import Any, Iterator

from fitz_ai.llm.auth import AuthProvider
from fitz_ai.llm.providers.base import (
    ChatProvider,
    EmbeddingProvider,
    StreamingChatProvider,
    VisionProvider,
)

logger = logging.getLogger(__name__)

CHATS = {
    "gpt-4": "gpt-4",
    "gpt-4-turbo": "gpt-4-turbo-preview",
}

EMBEDDING_MODEL = "text-embedding-3-small"
VISION_MODEL = "gpt-4-vision-preview"

class OpenAIChat(ChatProvider, StreamingChatProvider):
    def __init__(self, auth: AuthProvider, model: str | None = None, tier: ModelTier | None = None,
                 base_url: str | None = None, models: dict[ModelTier, str] | None = None) -> None:
        self.client = openai.OpenAI(  # [VERIFY] method not found in signatures
            api_key=auth.get_api_key(),
            http_client=httpx.AsyncClient(base_url=base_url)
        )

    def chat(self, messages: list[dict[str, Any]]) -> str:
        response = self.client.chat.completions.create(
            model=self.model,
            messages=messages
        )
        return response.choices[0].message.content

    def chat_stream(self, messages: list[dict[str, Any]]) -> Iterator[str]:
        stream = self.client.chat.completions.create(
            model=self.model,
            messages=messages,
            stream=True
        )
        for chunk in stream:
            if chunk.choices and chunk.choices[0].delta.content:
                yield chunk.choices[0].delta.content

class OpenAIEmbedding(EmbeddingProvider):
    def __init__(self, auth: AuthProvider, model: str | None = None,
                 dimensions: int | None = None, base_url: str | None = None) -> None:
        self.client = openai.OpenAI(
            api_key=auth.get_api_key(),
            http_client=httpx.AsyncClient(base_url=base_url)
        )

    def embed(self, text: str) -> list[float]:
        response = self.client.embeddings.create(input=text, model=self.model)
        return response.data[0].embedding

    def embed_batch(self, texts: list[str]) -> list[list[float]]:
        response = self.client.embeddings.create(input=texts, model=self.model)
        return [item.embedding for item in response.data]

    def dimensions(self) -> int:
        # Hardcoded or fetched from API
        return 1536

class OpenAIVision(VisionProvider):
    def __init__(self, auth: AuthProvider, model: str | None = None,
                 base_url: str | None = None) -> None:
        self.client = openai.OpenAI(
            api_key=auth.get_api_key(),
            http_client=httpx.AsyncClient(base_url=base_url)
        )

    def describe_image(self, image_base64: str, prompt: str | None = None) -> str:
        response = self.client.chat.completions.create(
            model=self.model,
            messages=[{
                "role": "user",
                "content": [
                    {"type": "text", "text": prompt or "Describe this image."},
                    {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{image_base64}"}}
                ]
            }]
        )
        return response.choices[0].message.content

